                    self.step();
                    continue;
                }

                cp if cp == '[' as CodePoint => {
                    self.step();
                    self.token = T::TOpenBracket;
                }
                cp if cp == ']' as CodePoint => {
                    self.step();
                    self.token = T::TCloseBracket;
                }
                cp if cp == '{' as CodePoint => {
                    self.step();
                    self.token = T::TOpenBrace;
                }
                cp if cp == '}' as CodePoint => {
                    self.step();
                    self.token = T::TCloseBrace;
                }
                cp if cp == ',' as CodePoint => {
                    self.step();
                    self.token = T::TComma;
                }
                cp if cp == ':' as CodePoint => {
                    self.step();
                    self.token = T::TColon;
