                        && (self.start == 0
                            || self.current == self.source.contents.len().saturating_sub(1))
                    {
                        self.step();
                        continue;
                    }
                    // Spec lexer.zig:1739-1750 — no is_json gate; scan an
                    // identifier-with-escapes (e.g. `true` → t_true).
                    self.scan_identifier_with_escapes()?;
