                cp => {
                    // Unusual whitespace.
                    if is_whitespace(cp) {
                        self.step();
                        continue;
                    }
                    if is_identifier_start(cp) {
                        self.step();
                        while is_identifier_continue(self.code_point) {
                            self.step();
                        }
                        self.token = T::TIdentifier;
                        self.identifier = self.raw();
                        return Ok(());
                    }
                    self.end = self.current;
                    self.token = T::TSyntaxError;
                }
            }

            return Ok(());
        }
    }
